  const safeUsers = users.map(({ id, name }) => ({ id, name })); // omit email
  res.json(safeUsers);
});
```

---

#### 5. No CORS Policy (OWASP A05:2021)

Without explicit CORS configuration, browsers use the same-origin default, but this isn't enforced at the server level. Adding `cors` middleware lets you explicitly allowlist origins rather than relying on client-side enforcement.

**Fix:**

```js
const cors = require('cors');

app.use(cors({
  origin: ['https://your-frontend.example.com'], // explicit allowlist
  methods: ['GET'],
  allowedHeaders: ['Authorization', 'Content-Type'],
}));
```

