  console.error(err); // log internally
  res.status(err.status || 500).json({ error: 'Internal Server Error' }); // never expose err.message
});
```

---

#### 7. Missing Request Body Parsing Limits

There is no `express.json()` or `express.urlencoded()` middleware, and no size cap. Once you add body parsing (for POST/PUT routes), omitting a `limit` allows a client to send a multi-gigabyte payload and exhaust memory.

**Fix:**

```js
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));
```

