  res.json([{ id: 1, name: 'Alice', email: 'alice@example.com' }, ...]);
});
```

**Fix:** Add an authentication middleware. At minimum, verify a bearer token; in production, use a proper session/JWT library:

```js
// ✅ Simple bearer-token guard (replace with real auth in production)
function requireAuth(req, res, next) {
  const auth = req.headers['authorization'];
  if (!auth || !auth.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  const token = auth.slice(7);
  if (!isValidToken(token)) {           // implement real validation
    return res.status(403).json({ error: 'Forbidden' });
  }
  next();
}

app.get('/users', requireAuth, (req, res) => { ... });
```

---

#### 2. Missing Security Headers (OWASP A05:2021 — Security Misconfiguration)

Express ships no security headers by default. Without them the app is vulnerable to clickjacking, MIME sniffing, XSS, and information disclosure (`X-Powered-By: Express`).

**Fix:** Add [`helmet`](https://helmetjs.github.io/) as the very first middleware:

```js
const helmet = require('helmet');
app.use(helmet());
// Sets: Content-Security-Policy, X-Frame-Options, X-Content-Type-Options,
//       Strict-Transport-Security, Referrer-Policy, and removes X-Powered-By
```

---

### 🟠 HIGH

#### 3. No Rate Limiting (OWASP A04:2021 — Insecure Design)

Both endpoints are wide open to enumeration, scraping, and denial-of-service. The `/users` endpoint is especially attractive for automated harvesting.

**Fix:** Use [`express-rate-limit`](https://github.com/express-rate-limit/express-rate-limit):

```js
const rateLimit = require('express-rate-limit');

const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});

app.use('/api/', apiLimiter); // or apply globally: app.use(apiLimiter)
```

---

#### 4. Sensitive Data Exposure / Insufficient Data Minimization (OWASP A02:2021)

Even if authentication were added, returning raw email addresses in a list response is risky. Emails are PII and should only be returned when genuinely needed (e.g., a `/users/:id/profile` endpoint for the authenticated user themselves).

**Fix:** Strip sensitive fields from list responses:

```js
app.get('/users', requireAuth, (req, res) => {
  const safeUsers = users.map(({ id, name }) => ({ id, name })); // omit email
  res.json(safeUsers);
});
```

---

#### 5. No CORS Policy (OWASP A05:2021)

Without explicit CORS configuration, browsers use the same-origin default, but this isn't enforced at the server level. Adding `cors` middleware lets you explicitly allowlist origins rather than relying on client-side enforcement.

**Fix:**

```js
const cors = require('cors');

app.use(cors({
  origin: ['https://your-frontend.example.com'], // explicit allowlist
  methods: ['GET'],
  allowedHeaders: ['Authorization', 'Content-Type'],
}));
```

